import React, { useState } from "react";
import "./Login.css";
import bg from "../../assets/LoginPage.png";

function Login({ toggleSignup, goForgot, goHome }) {
  const [formData, setFormData] = useState({ email: "", password: "" });
  const [message, setMessage] = useState("");

  const handleChange = (e) => setFormData({ ...formData, [e.target.name]: e.target.value });

  const handleSubmit = async (e) => {
    e.preventDefault();
    // Simulate login success
    if (formData.email && formData.password) {
      setMessage("Login successful!");
      setTimeout(() => goHome(), 500);
    } else {
      setMessage("Invalid credentials");
    }
  };

  return (
    <div className="login-container" style={{ backgroundImage: `url(${bg})` }}>
      <div className="login-box">
        <h1>LOGIN</h1>
        <form onSubmit={handleSubmit}>
          <input type="email" name="email" placeholder="Email" value={formData.email} onChange={handleChange} required />
          <input type="password" name="password" placeholder="Password" value={formData.password} onChange={handleChange} required />
          <p className="forgot" onClick={goForgot}>Forgot password?</p>
          <button type="submit">Login</button>
        </form>
        {message && <p style={{ color: "red", marginTop: "10px" }}>{message}</p>}
        <p>
          Don't have an account? <span className="signup-link" onClick={toggleSignup}>Sign up</span>
        </p>
      </div>
    </div>
  );
}

export default Login;
